package com.google.gson.examples.android.model;

import static org.junit.jupiter.api.Assertions.assertEquals;

import org.junit.jupiter.api.Test;

class LineItemTest {

  @Test
  void getPriceInMicros_returnsCorrectValue() throws Exception {
    String name = "TestItem";
    int quantity = 2;
    long priceInMicros = 123456L;
    String currencyCode = "USD";

    // Use reflection to create LineItem instance since constructor is not accessible
    Class<?> clazz = Class.forName("com.google.gson.examples.android.model.LineItem");
    var constructor = clazz.getDeclaredConstructor(String.class, int.class, long.class, String.class);
    constructor.setAccessible(true);
    Object lineItem = constructor.newInstance(name, quantity, priceInMicros, currencyCode);

    var method = clazz.getDeclaredMethod("getPriceInMicros");
    method.setAccessible(true);
    long result = (long) method.invoke(lineItem);

    assertEquals(priceInMicros, result);
  }
}
